        while(XCheckTypedEvent(display, Expose, &event))
            ;
-       XFindContext(display, event.xexpose.window,
-                    devPtrContext, &temp);
+       if (XFindContext(display, event.xexpose.window,
+                    devPtrContext, &temp)) return;
        dd = (NewDevDesc *) temp;
